import{_ as a,o,c as r,ae as i}from"./chunks/framework.RRduUuAx.js";const p=JSON.parse('{"title":"Proposal: Provider Ledger Schema Module v1","description":"","frontmatter":{},"headers":[],"relativePath":"changes/shared-modules/provider-ledger-schema-v1/proposal.md","filePath":"changes/shared-modules/provider-ledger-schema-v1/proposal.md"}'),l={name:"changes/shared-modules/provider-ledger-schema-v1/proposal.md"};function d(s,e,t,c,n,h){return o(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="proposal-provider-ledger-schema-module-v1" tabindex="-1">Proposal: Provider Ledger Schema Module v1 <a class="header-anchor" href="#proposal-provider-ledger-schema-module-v1" aria-label="Permalink to &quot;Proposal: Provider Ledger Schema Module v1&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Create a reusable, versioned module for the provider ledger SQL schema so downstream tooling can depend on a stable path and contract.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><ul><li>The unified schema exists today but is not packaged as an explicit shared module.</li><li>Consumers need a single canonical module path with version ownership and artifact guarantees.</li></ul><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><ul><li>Add rollout docs for this module under <code>docs/changes/shared-modules/provider-ledger-schema-v1/</code>.</li><li>Add a machine-readable contract artifact defining ownership, semantic versioning, and required artifacts.</li><li>Introduce module directory <code>ledger/provider-ledger-schema-v1/</code> with canonical schema SQL.</li><li>Add a validation script that fails loudly on missing or drifted artifacts.</li></ul><h2 id="non-goals" tabindex="-1">Non-Goals <a class="header-anchor" href="#non-goals" aria-label="Permalink to &quot;Non-Goals&quot;">​</a></h2><ul><li>No schema content redesign in this rollout.</li><li>No migration logic, fallback logic, or compatibility shims.</li></ul><h2 id="deliverables" tabindex="-1">Deliverables <a class="header-anchor" href="#deliverables" aria-label="Permalink to &quot;Deliverables&quot;">​</a></h2><ul><li><code>docs/changes/shared-modules/provider-ledger-schema-v1/proposal.md</code></li><li><code>docs/changes/shared-modules/provider-ledger-schema-v1/tasks.md</code></li><li><code>docs/contracts/provider-ledger-schema.contract.json</code></li><li><code>ledger/provider-ledger-schema-v1/unified_model_provider_ledger.schema.sql</code></li><li><code>scripts/validate_provider_ledger_module.sh</code></li></ul><h2 id="acceptance-criteria" tabindex="-1">Acceptance Criteria <a class="header-anchor" href="#acceptance-criteria" aria-label="Permalink to &quot;Acceptance Criteria&quot;">​</a></h2><ul><li>Validation script exits <code>0</code> only when all required artifacts exist.</li><li>Validation script exits non-zero and prints explicit error(s) when artifacts are missing or schema content diverges.</li><li>Canonical module schema remains equivalent to <code>ledger/unified_model_provider_ledger.schema.sql</code>.</li></ul>',13)])])}const u=a(l,[["render",d]]);export{p as __pageData,u as default};
